import 'package:flutter/material.dart';import 'app_colors.dart';import 'app_spacing.dart';import 'app_typography.dart';enum DateRange { weekly, monthly, quarterly, custom }class DsDateRangeSelector extends StatefulWidget {  final DateRange initialRange;  final ValueChanged<DateRange> onRangeSelected;  const DsDateRangeSelector({    super.key,    this.initialRange = DateRange.monthly,    required this.onRangeSelected,  });  @override  State<DsDateRangeSelector> createState() => _DsDateRangeSelectorState();}@overrideclass _DsDateRangeSelectorState extends State<DsDateRangeSelector> {  late DateRange _selectedRange;  @override  void initState() {    super.initState();    _selectedRange = widget.initialRange;  }  String _getRangeText(DateRange range) {    switch (range) {      case DateRange.weekly:        return 'Weekly';      case DateRange.monthly:        return 'Monthly';      case DateRange.quarterly:        return 'Quarterly';      case DateRange.custom:        return 'Custom';    }  }  @override  Widget build(BuildContext context) {    return Container(      padding: const EdgeInsets.all(AppSpacing.gridBase),      decoration: BoxDecoration(        color: AppColors.surface,        borderRadius: BorderRadius.circular(AppSpacing.borderRadiusLarge),      ),      child: Row(        mainAxisSize: MainAxisSize.min,        children: DateRange.values.map((range) {          final bool isSelected = _selectedRange == range;          return GestureDetector(            onTap: () {              if (!isSelected) {                setState(() {                  _selectedRange = range;                });                widget.onRangeSelected(range);              }            },            child: AnimatedContainer(              duration: const Duration(milliseconds: 250),              curve: Curves.easeInOut,              padding: const EdgeInsets.symmetric(                horizontal: AppSpacing.paddingMedium,                vertical: AppSpacing.paddingSmall,              ),              decoration: BoxDecoration(                color: isSelected ? AppColors.dateRangeActiveBackground : Colors.transparent,                borderRadius: BorderRadius.circular(AppSpacing.borderRadiusLarge),              ),              child: Text(                _getRangeText(range),                style: isSelected                    ? AppTypography.dateRangeActive                    : AppTypography.dateRangeInactive,              ),            ),          );        }).toList(),      ),    );  }}